patch:
diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 5907e2106533..2cb322236351 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -6303,10 +6303,24 @@ static Value *simplifyUnaryIntrinsic(Function *F, Value *Op0,

   Value *X;
   switch (IID) {
-  case Intrinsic::fabs:
-    if (computeKnownFPSignBit(Op0, Q) == false)
-      return Op0;
+  case Intrinsic::fabs: {
+    // Check for the specific problematic pattern:
+    // fabs(select (fcmp ogt (fabs X), 0.0), X, 0.0)
+    Value *X, *Cond, *TrueVal, *FalseVal;
+    if (match(Op0, m_Select(m_Value(Cond), m_Value(TrueVal), m_Value(FalseVal))) &&
+        match(FalseVal, m_AnyZeroFP()) &&
+        match(Cond, m_SpecificFCmp(FCmpInst::FCMP_OGT, 
+                                   m_Intrinsic<Intrinsic::fabs>(m_Value(X)), 
+                                   m_AnyZeroFP())) &&
+        TrueVal == X) {
+      // This is the problematic pattern - don't simplify
+    } else {
+      // Use the original logic for all other cases
+      if (computeKnownFPSignBit(Op0, Q) == false)
+        return Op0;
+    }
     break;
+  }
   case Intrinsic::bswap:
     // bswap(bswap(x)) -> x
     if (match(Op0, m_BSwap(m_Value(X))))

