   case Intrinsic::fabs:
-    if (computeKnownFPSignBit(Op0, Q) == false)
+    // The original logic using computeKnownFPSignBit was too aggressive
+    // for select instructions. However, the cannotBeOrderedLessThanZero
+    // approach also doesn't work correctly in all cases.
+    // For now, let's revert to a more conservative approach that only
+    // eliminates fabs for known constants or simple cases.
+    if (const auto *CFP = dyn_cast<ConstantFP>(Op0)) {
+      if (!CFP->isNegative())
+        return Op0;
+    }
+    // Also handle the case where we have fabs(fabs(x)) -> fabs(x)
+    if (match(Op0, m_Intrinsic<Intrinsic::fabs>(m_Value())))
       return Op0;
     break;
